import{_ as p,o as e,c as a,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const c=JSON.parse('{"title":"飘渺无常的银翼","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/能量类/飘渺无常的银翼.md","filePath":"4.资源分区/6.技艺及称号/能量类/飘渺无常的银翼.md"}'),s={name:"4.资源分区/6.技艺及称号/能量类/飘渺无常的银翼.md"};function o(d,b,D,_,l,i){return e(),a("div",null,[...b[0]||(b[0]=[r("h1",{id:"飘渺无常的银翼",tabindex:"-1"},[t("飘渺无常的银翼 "),r("a",{class:"header-anchor",href:"#飘渺无常的银翼","aria-label":'Permalink to "飘渺无常的银翼"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风020")])])],-1),n('<h1 id="飘渺无常的银翼-1" tabindex="-1">飘渺无常的银翼 <a class="header-anchor" href="#飘渺无常的银翼-1" aria-label="Permalink to &quot;飘渺无常的银翼&quot;">​</a></h1><p>飘渺无常的银翼<br> 描述：飘渺如云，轻盈似烟，无常之举亦是风的自由。曾有这样一位源自遥远东方的女子，在破晓之际踏上了这片陌生的土地，她孤身一人，肩负着重要的使命，寻找名为“苍穹之眼”的古老遗……“等会等会，我不是出国留学去的？”</p><p>D+500<br> 然道：然道是源自于远东之地的施法体系，然道信仰万物有神灵，因此所有神明体系皆可以与然道信仰体系兼容。<br> 习得然道后开启灵力能量池，正常获得基础用法，在你使用灵力相关的效果时，可以减少1点灵力消耗（最多降低到1点），每轮只能减少一次消耗。</p><p>习得然道后，你获得一种新的攻击方式：然道攻击。<br> 这种攻击具有3点的基础法强，使用风度+学识（然道）+辅助专业：沟通自然（社交）进行攻击检定，基础射程15米，造成纯能量伤害。</p><p>【下属技艺】<br> 火箭/冰刃/迅雷<br> 价格：D+500<br> 动作：标准动作<br> 射程：15+传奇风度*5米<br> 消耗：1点灵力<br> 持续：立即<br> 描述：朝敌人放出箭矢状的火焰/用冰刃切碎敌人/从敌人头顶降下落雷攻击。<br> 效果：你进行一次然道攻击，本次攻击中获得3DP的技艺加值，以及1点附加成功，伤害类型改为火焰/寒冷/雷电能量伤害。</p><p>炎狱/巨大冰锥/轰雷<br> 前提：火箭/冰刃/迅雷（差价升级）<br> 价格：C+1000<br> 动作：标准动作<br> 范围：15+传奇风度*5米（扇形）<br> 消耗：3点灵力<br> 持续：立即<br> 描述：召唤出强烈的火焰包裹全体敌人/用强力是冰块刺穿全体敌人/伴随轰鸣以无数闪电攻击全体敌人。<br> 效果：<br> 你进行一次然道攻击，对前方15+传奇风度*5米的扇形范围内所有敌方造成伤害，本次攻击获得5DP的技艺加值，以及1点附加成功，伤害类型改为火焰/寒冷/雷电能量伤害。</p><p>清净雷霆<br> 价格：C+1500<br> 动作：标准动作<br> 射程：15+传奇风度*5米<br> 目标：单一<br> 消耗：3点灵力<br> 持续：立即<br> 描述：用神圣的落雷扫清所有邪恶，可以驱逐诅咒。<br> 效果：<br> 你进行一次然道攻击，本次攻击获得5DP技艺加值，与1点攻击附加成功，伤害类型改为雷电能量伤害。这次攻击在命中后会驱散目标身上的祝福/诅咒效果，你可以自行选择是否造成伤害，或是驱逐祝福/诅咒其中之一的效果。</p><p>月光<br> 价格：C+1250<br> 动作：标准动作<br> 范围：15+传奇风度*5米（扇形）<br> 消耗：3点灵力<br> 持续：立即<br> 描述：用诡异的月光包裹全体敌人，概率使敌人陷入混乱。<br> 效果：<br> 你进行一次然道攻击，对前方15+传奇风度*5米的扇形范围内所有敌方造成伤害，本次攻击获得2DP的技艺加值，以及1点附加成功，伤害类型改为亵渎能量伤害。<br> 此外，被命中的目标需要额外进行一次意志豁免，豁免失败则承受C级诅咒来源的混乱效果，无法辨别攻击目标，攻击时将随机指定场上的目标进行攻击。</p><p>剑舞<br> 价格：C+1500<br> 动作：整轮动作<br> 射程：见下<br> 目标：见下<br> 消耗：3点灵力<br> 持续：立即<br> 描述：干净利落的斩击翩翩起舞，威力依存于攻击力，无关属性的斩击攻击。<br> 效果：你进行一次然道攻击，本次攻击如同冲锋一样结算，正常享受冲锋移动的好处与坏处，将同时对冲锋路径上触及距离的所有敌人进行一次攻击。<br> 本次冲锋无论移动了多少距离，皆视为移动了最大距离结算，在攻击中会额外获得8DP技艺加值与1个攻击附加成功，伤害类型改为物理挥砍伤害。</p><p>被疼爱体质<br> 价格：D+500<br> 分类：被动<br> 描述：所谓【被疼爱体质】……只看名称就知道是怎么一回事的产物。<br> 效果：购买者在被攻击时，给予攻击者1点不可豁免的魅惑不良点数。<br> 购买这一能力不会获得自由属性，但如果愿意将购买价格提升到C+1000，则除了能正常获得被疼爱体质的效果外，购买者可以免疫疲乏点数带来的减值及严重状态，同时如同购买了一个C技艺一样正常获得自由属性。</p><p>九十九攻击<br> 前提：被疼爱体质<br> 分类：被动<br> 价格：C+1000<br> 描述：周围东西寄宿的精灵奋起援助，是拥有被疼爱体质的专用技。<br> 效果：<br> 每轮开始时，你额外获得2点只能用于将移动动作升级为杂技动作的AP。同时，你在进行攻击时周围的精灵会进行援助，这会使你在攻击中额外获得1点增强加值和1个攻击附加成功。<br> 当你使用然道类技艺时，消耗的灵力将额外再降低2点（最多降低到1点），降低消耗的效果每轮只会生效一次。</p><p>镰鼬大军<br> 价格：C+1000<br> 动作：标准动作<br> 射程：15+传奇风度*5米<br> 目标：单一<br> 消耗：3点灵力<br> 持续：立即<br> 描述：本来只想召唤一只，结果镰鼬大军出现了！是拥有被疼爱体质的专用技。<br> 效果：<br> 你进行一次然道攻击，本次攻击获得8DP的技艺加值，以及1点附加成功，伤害类型改为音波伤害。<br> 在攻击命中后，还会如同额外攻击了6次一样计算多次攻击减值，这是镰鼬大军的努力。</p><p>少女祈福<br> 价格：C+1000<br> 动作：迅捷动作<br> 目标：单一<br> 射程：基础射程（然道）<br> 消耗：3<br> 持续：立即<br> 描述：向万物祈祷，以获取生命力，可以中等程度的恢复友方的生命值。<br> 效果：<br> 你指定射程内的任一目标，使其立刻恢复4点生命值至完好，如同承受了4点快速医疗一样计算，每次长休息前最多使用该技能恢复合计不超过48点生命值。<br> 此外，被指定的目标将在这一轮内获得2点力场防御，多次使用该技能不会叠加因此获得的防御。</p><p>命之神乐<br> 价格：C+1000<br> 动作：整轮动作<br> 目标：范围<br> 范围：基础射程（然道）<br> 消耗：5<br> 持续：立即<br> 描述：感谢生命的美丽舞蹈，发动较慢，不过可以更大幅度的恢复生命值，同时略微恢复异常状态。<br> 效果：<br> 以自身为中心，射程范围内的所有单位立刻恢复5点生命值，以及消除2点任意不良点数。<br> 每日最多因此恢复合计不超过60点生命值，以及48点异常不良点数。</p><p>防护结界<br> 价格：B+2500<br> 动作：标准动作<br> 范围：15+传奇风度*10米<br> 消耗：10点灵力<br> 持续：一场景<br> 描述：在周围展开六芒星结界，暂时提高防御力与魔法防御能力。<br> 效果：<br> 以自身为中心，展开半径等同于15+传奇风度*10米的六芒星防护结界，范围内的友方单位获得12点力场防御的提升，同时获得3点全能量抗力。<br> 以此获得的全能量抗力可以在购买时选择转换成DR/-。</p><p>反射结界<br> 价格：A+4000<br> 动作：标准动作<br> 范围：15+风度*20米<br> 消耗：无<br> 持续：一轮<br> 描述：只在一回合内有效的，张开可以反弹攻击的六芒星结界，结界还会持续性的对范围内的敌人造成伤害，同时还能作为使用然道的媒介施加攻击。<br> 效果：你展开一道反射结界，以自身为中心，覆盖范围等同于15+风度*20米，展开的同时进行一次然道攻击，对范围内的所有敌人同时造成伤害，本次然道攻击无法附带任何其他招式，如同标准普通攻击一样。<br> 此外，只要反射结界仍然存在，你每轮就能获得8点只能用于除【反射结界】外，不超过A级的然道下属技艺，或是然道攻击的AP，同时所有范围内的敌对单位在攻击友方单位（包括你在内）时，必须先进行一次强韧/反射（购买时自行选择）检定的豁免，豁免失败则本次攻击目标转为敌方自身，这是一个A级祝福来源的胁迫能力。<br> 若你在使用其他然道技艺时射程/范围低于反射结界的覆盖范围，则将射程/范围提升至反射结界的覆盖范围。<br> 【购买这一能力不会获得自由属性。】</p><p>清净波动<br> 价格：S+8000<br> 动作：标准动作<br> 范围：风度*100米<br> 消耗：无<br> 持续：一场景<br> 描述：以清净的波动，将其他的魔法效果完全消除，展开的波动还能持续性的为友方抵消受到的伤害。<br> 效果：你展开一道清净的波动，以自身为中心，范围等同于风度*100米的圆形，所有友军，包括自身在内免疫任何基于能量提供的效果，如因能量获得的加值，能量驱动的攻击，因能量获得的防御，基于能量使用都效果等等，这是一个A级的免疫效果。<br> 此外，只要这一效果仍然生效，那么范围内所有友方单位每轮可以免疫一次攻击伤害，这是一个S级祝福的无敌效果。<br> 【购买这一能力不会获得自由属性。】</p><p>【下属物品】<br> 特殊的是，并非只有具有【飘渺无常的银翼】主体内容的单位才能购买下属物品，【飘渺无常的银翼】下属物品可以被正常购买。</p><p>红叶玉串<br> 价格：D+500<br> 分类：武器（法器）<br> 法强：提升3点<br> 描述：在清净的红叶树枝上挂着纸垂的玉串，对巫女来说是刚好的人气商品。<br> 效果：<br> 红叶玉串会为持有者提供全检定上的1DP加值，若穿戴了传统巫女服则改为获得5点外貌提升。<br> 此外，当使用红叶玉串进行施法攻击时，攻击会额外获得2DP器械加值。</p><p>樱华玉串<br> 前提：红叶玉串（逐升）<br> 价格：C+1000<br> 分类：武器（法器）<br> 法强：提升11点<br> 描述：进一步加工的魔法玉串，能和装备者的本质互相呼应，使出强力的术式。<br> 效果：<br> 樱华玉串会为持有者提供全检定上的2DP加值，若穿戴了传统巫女服则改为获得10点外貌提升。<br> 此外，当使用樱华玉串进行施法攻击时，攻击会额外获得1DP器械加值与1个攻击附加成功。</p><p>紫杉笏板<br> 价格：D+500<br> 分类：武器（棍）<br> 武器伤害：6L<br> 武器特性：【格挡1】<br> 描述：然道仪式使用的神具武器化后的东西，打人很疼。<br> 效果：<br> 持有紫杉笏板会替换使用然道进行攻击时的法强，改为使用武器伤害计入攻击检定，同时伤害类型改为物理-钝击。<br> 使用紫杉笏板进行然道攻击时，将额外附带2DP器械加值，以及1点攻击附加成功。</p><p>月读的笏板<br> 前提：紫杉笏板（逐升）<br> 价格：C+1250<br> 分类：武器（棍）<br> 武器伤害：14L<br> 武器特性：【格挡1】【法破】<br> 描述：拥有强力驱魔效果的铭木制作而成的神具，打人非常的疼。<br> 效果：<br> 持有月读的笏板会替换使用然道进行攻击时的法强，改为使用武器伤害计入攻击检定，同时伤害类型改为物理-钝击。<br> 使用月读的笏板进行然道攻击时，将额外附带5DP器械加值，以及1点攻击附加成功。</p><p>龟甲簪子<br> 价格：D+500<br> 分类：簪子<br> 描述：稀有的龟甲制造的簪子，光是看起来就很漂亮，能够减少受到的属性伤害。<br> 效果：龟甲簪子不占用装备位，但仍会提升3点【传统巫女服】提供的盔甲防御，以及提升1点全伤害吸收效果。</p><p>神代杉之簪<br> 价格：C+1000<br> 分类：簪子<br> 描述：神代杉制作的巫女用簪子，能和装备者的本质互相呼应，使出强力的防御术式。<br> 效果：神代杉之簪不占用装备位，但仍会提升8点【传统巫女服】提供的盔甲防御，以及提升1点全伤害吸收效果，佩戴者还会在三豁免上获得2DP器械加值。<br> 此外，每场景一次，佩戴者可以将持有武器/法器带来的武器伤害/法术强度转为在格挡时提升的【传统巫女服】等量的盔甲防御，这一效果将持续一场景。</p><p>藤制前天冠<br> 价格：D+500<br> 占用：头盔位<br> 描述：装饰有藤花的天冠，剧烈运动的话花就会展现出来。<br> 效果：提升【传统巫女服】带来的盔甲防御5点，同时佩戴者在外貌上获得5点提升，这是额外提升，正常获得全检定加值。</p><p>战姬天冠<br> 前置：藤制前天冠（逐升）<br> 价格：C+1000<br> 占用：头盔<br> 描述：出自神具职人之手的巫女专用装备，虽说是普及品但能力很高。<br> 效果：<br> 提升【传统巫女服】带来的盔甲防御10点，同时佩戴者在外貌上获得10点提升，这是额外提升，正常获得全检定加值。<br> 此外，佩戴者的生命值即使被严重伤害也不会昏迷，这是巫女专用装备上施加的精神干涉魔法带来的效果，能够使佩戴者在紧急的状况下维持战斗能力。</p><p>御币手甲<br> 价格：D+500<br> 占用：手腕<br> 描述：手甲的部分带着纸垂，有点画蛇添足感觉的手甲，姑且能提升点装备者的防御能力。<br> 效果：提升盔甲防御5点。此外，佩戴者在风度检定上获得3DP的器械加值，这是由于装备风格带来的靓丽风情。</p><p>秘银手甲<br> 价格：C+1000<br> 占用：手腕<br> 描述：用近些年发现的提炼方式，提炼出975的秘银，这种秘银制作的护手材质比起铁和银，要轻而牢固的多。<br> 效果：<br> 佩戴者盔甲防御提升2点，盔甲减值降低4点，同时获得1DR/-与1点全能量抗力。</p><p>传统巫女服<br> 价格：C+1000<br> 描述：白衣绯袴的传统巫女服，样式相当传统，上面有施加恒定的洁净术以及防护术。虽然其貌不扬，但基本刀枪不入，水火不侵，不会破损也不会脏污。<br> 效果：<br> 这是一件盔甲防御为1/1的轻甲，占据上肢-躯干位，提供基于盔甲防御的【全伤害吸收5】【防能量武器】，若盔甲防御因任何原因发生转变，则全伤害吸收/防能量武器的基础也会发生转变。<br> 这件盔甲不会因任何原因而脏污，时刻洁净如新。</p><p>不可思议的替身娃娃<br> 价格：C+1000<br> 位置：护符位<br> 描述：变成和持有者一样的替身娃娃，完全防止即死攻击，同时可以略微获得额外的经验值。<br> 效果：佩戴者免疫不超过S级的所有即死效果，在三豁免上获得2DP器械加值。</p><hr><p>Copyright ? 2024 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',32)])])}const C=p(s,[["render",o]]);export{c as __pageData,C as default};
